100	    /// Load the pre-assembled APL binary and start the emulator.
101	    fn load_apl_binary(&mut self) {
102	        let binary = config::APL_BINARY;
103	        self.emulator.hard_reset();
104	        self.emulator.set_uart_tx_busy_cycles(0);
105	        self.emulator.load_program(0, binary);
106	        self.emulator.load_program_extent(binary.len() as u32);
107	        self.emulator.set_pc(0);
108	        self.emulator.resume();
