122	            if status & 0x01 != 0 {
123	                break; // RX buffer full, try again next tick
124	            }
125	            if let Some(byte) = self.uart_rx_queue.pop_front() {
126	                self.emulator.send_uart_byte(byte);
127	                self.last_rx = Some(byte);
128	            }
129	        }
130	    }
