200	impl Component for ReplPanel {
201	    type Message = Msg;
202	    type Properties = ReplPanelProps;
203	
204	    fn create(ctx: &Context<Self>) -> Self {
205	        ctx.link().send_message(Msg::Init);
206	        let mut emulator = EmulatorCore::new();
207	        emulator.set_uart_tx_busy_cycles(0);
208	        Self {
209	            emulator,
210	            output: vec!["APL / COR24 Environment".to_string(), String::new()],
211	            input: String::new(),
212	            running: false,
213	            halted: false,
214	            uart_rx_queue: VecDeque::new(),
215	            partial_line: String::new(),
216	            _tick_handle: None,
217	            output_ref: NodeRef::default(),
218	            panel_ref: NodeRef::default(),
219	            needs_focus: false,
220	            last_reset_seq: 0,
221	            last_feed_seq: 0,
222	            last_tx: None,
223	            last_rx: None,
224	            history: Vec::new(),
225	            history_index: None,
226	            history_saved_input: String::new(),
227	            user_scrolled_up: false,
228	        }
229	    }
230	
231	    fn changed(&mut self, ctx: &Context<Self>, _old_props: &Self::Properties) -> bool {
232	        let props = ctx.props();
233	
234	        // Handle reset command
235	        if props.reset_seq != self.last_reset_seq {
236	            self.last_reset_seq = props.reset_seq;
237	            self.load_apl_binary();
238	            self.needs_focus = true;
239	            // Always schedule a fresh tick — the old Timeout may have
240	            // already fired (e.g. after )OFF halt) but still be Some.
241	            self._tick_handle = Some(Self::schedule_tick(ctx));
242	        }
243	
244	        // Handle feed text command
245	        if props.feed_seq != self.last_feed_seq {
246	            self.last_feed_seq = props.feed_seq;
247	            self.feed_program_text(&props.feed_text);
248	            self.needs_focus = true;
249	        }
250	
251	        // S2 switch — use emulator API (active-low hardware)
252	        self.emulator.set_button_pressed(props.s2_on);
253	
254	        true
255	    }
256	
257	    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
258	        match msg {
259	            Msg::Init => {
260	                self.load_apl_binary();
261	                self._tick_handle = Some(Self::schedule_tick(ctx));
262	                true
263	            }
264	            Msg::Tick => {
265	                if !self.running || self.halted {
266	                    return false;
267	                }
268	
269	                self.feed_uart_bytes();
270	                let result = self.emulator.run_batch(BATCH_SIZE);
271	                self.collect_uart();
272	
273	                if matches!(result.reason, StopReason::Halted) {
274	                    self.halted = true;
275	                    self.running = false;
276	                    // Flush any remaining partial line
277	                    if !self.partial_line.is_empty() {
278	                        self.output.push(std::mem::take(&mut self.partial_line));
279	                    }
280	                    self.output.push(String::new());
281	                    self.output
282	                        .push("[Halted — press Reset to restart]".to_string());
283	                }
284	
285	                if self.running && !self.halted {
286	                    self._tick_handle = Some(Self::schedule_tick(ctx));
287	                }
288	
289	                // Report hardware state to parent (LED is active-low)
290	                let led_on = self.emulator.is_led_on();
291	                ctx.props()
292	                    .on_hw_state
293	                    .emit((led_on, self.last_tx, self.last_rx));
294	
295	                true
296	            }
297	            Msg::Scroll => {
298	                if let Some(el) = self.output_ref.cast::<HtmlElement>() {
299	                    let was = self.user_scrolled_up;
300	                    self.user_scrolled_up = !Self::is_near_bottom(&el);
301	                    // Only re-render if the flag changed (shows/hides the indicator)
302	                    was != self.user_scrolled_up
303	                } else {
304	                    false
305	                }
306	            }
307	            Msg::ScrollToBottom => {
308	                self.user_scrolled_up = false;
309	                if let Some(el) = self.output_ref.cast::<HtmlDivElement>() {
310	                    el.set_scroll_top(el.scroll_height());
311	                }
312	                true
313	            }
314	            Msg::KeyDown(e) => {
315	                // Let modifier combos (Cmd-C, Ctrl-V, etc.) pass through to browser
316	                if e.meta_key() || e.ctrl_key() || e.alt_key() {
317	                    return false;
318	                }
319	                // Ignore input when the emulator has halted (e.g. after )OFF)
320	                if self.halted {
321	                    return false;
322	                }
323	                let key = e.key();
324	                match key.as_str() {
325	                    "Enter" => {
326	                        e.prevent_default();
327	                        // Translate literate names to ASCII keywords
328	                        let translated = translate_literate_to_ascii(&self.input);
329	                        // Show the translated line in output
330	                        let line = format!("{PROMPT}{translated}");
331	                        self.output.push(line);
332	                        // Queue translated bytes for the emulator's UART
333	                        for b in translated.bytes() {
334	                            self.uart_rx_queue.push_back(b);
335	                        }
336	                        self.uart_rx_queue.push_back(b'\n');
337	                        // Save non-empty input to history
338	                        if !self.input.is_empty() {
339	                            self.history.push(self.input.clone());
340	                        }
341	                        self.input.clear();
342	                        self.history_index = None;
343	                        true
344	                    }
345	                    "ArrowUp" => {
346	                        e.prevent_default();
347	                        if self.history.is_empty() {
348	                            return false;
349	                        }
350	                        let new_index = match self.history_index {
351	                            None => {
352	                                self.history_saved_input = self.input.clone();
353	                                self.history.len() - 1
354	                            }
355	                            Some(0) => return false,
356	                            Some(i) => i - 1,
357	                        };
358	                        self.history_index = Some(new_index);
359	                        self.input = self.history[new_index].clone();
360	                        true
361	                    }
362	                    "ArrowDown" => {
363	                        e.prevent_default();
364	                        match self.history_index {
365	                            None => return false,
366	                            Some(i) if i + 1 < self.history.len() => {
367	                                self.history_index = Some(i + 1);
368	                                self.input = self.history[i + 1].clone();
369	                            }
370	                            Some(_) => {
371	                                self.history_index = None;
372	                                self.input = std::mem::take(&mut self.history_saved_input);
373	                            }
374	                        }
375	                        true
376	                    }
377	                    "Backspace" => {
378	                        e.prevent_default();
379	                        self.input.pop();
380	                        true
381	                    }
382	                    _ => {
383	                        if key.len() == 1 {
384	                            e.prevent_default();
385	                            let ch = key.chars().next().unwrap();
386	                            if ch.is_ascii_graphic() || ch == ' ' {
387	                                self.input.push(ch);
388	                                return true;
389	                            }
390	                        }
391	                        false
392	                    }
393	                }
394	            }
395	        }
396	    }
397	
398	    fn rendered(&mut self, _ctx: &Context<Self>, first_render: bool) {
399	        self.scroll_to_bottom();
400	        if (first_render || self.needs_focus)
401	            && let Some(el) = self.panel_ref.cast::<HtmlDivElement>()
402	        {
403	            let _ = el.focus();
404	            self.needs_focus = false;
405	        }
406	    }
407	
408	    fn view(&self, ctx: &Context<Self>) -> Html {
409	        let onkeydown = ctx.link().callback(Msg::KeyDown);
410	        let onscroll = ctx.link().callback(|_: Event| Msg::Scroll);
411	        let on_scroll_btn = ctx.link().callback(|_: MouseEvent| Msg::ScrollToBottom);
412	        let mode = ctx.props().display_mode;
413	
414	        html! {
415	            <div class="repl-panel" tabindex="0" {onkeydown} ref={self.panel_ref.clone()}>
416	                <div class="repl-output" ref={self.output_ref.clone()} {onscroll}>
417	                    { for self.output.iter().map(|line| Self::render_line(line, mode)) }
418	                    // Show partial line if the emulator is mid-output
419	                    if !self.partial_line.is_empty() {
420	                        <div class="repl-line">{ &self.partial_line }</div>
421	                    }
422	                    <div class="repl-input-line">
423	                        <span class="repl-prompt">{ PROMPT }</span>
424	                        <span class="repl-input-text">
425	                            { Self::render_segments(&prettify_line(&translate_literate_to_ascii(&self.input), mode)) }
426	                        </span>
427	                        <span class="repl-cursor">{"\u{2588}"}</span>
428	                    </div>
429	                </div>
430	                if self.user_scrolled_up {
431	                    <button class="scroll-to-bottom" onclick={on_scroll_btn}
432	                        title="Scroll to bottom">
433	                        {"↓ Bottom"}
434	                    </button>
435	                }
436	            </div>
437	        }
438	    }
439	}
