    last_rx: Option<u8>,
    display_mode: DisplayMode,
    help_visible: bool,
}

impl Component for App {
    type Message = Msg;
    type Properties = ();

    fn create(_ctx: &Context<Self>) -> Self {
        Self {
            reset_seq: 0,
            feed_seq: 0,
            feed_text: AttrValue::default(),
            s2_on: false,
            led_on: false,
            last_tx: None,
            last_rx: None,
            display_mode: DisplayMode::default(),
            help_visible: false,
        }
    }

    fn update(&mut self, _ctx: &Context<Self>, msg: Self::Message) -> bool {
        match msg {
            Msg::Reset => {
                self.reset_seq = self.reset_seq.wrapping_add(1);
                self.s2_on = false;
                self.led_on = false;
                self.last_tx = None;
                self.last_rx = None;
                true
            }
            Msg::LoadDemo(text) | Msg::UploadProgram(text) => {
                self.feed_text = AttrValue::from(text);
                self.feed_seq = self.feed_seq.wrapping_add(1);
                true
            }
            Msg::ToggleS2 => {
                self.s2_on = !self.s2_on;
                true
            }
            Msg::HwState(led, tx, rx) => {
                let changed = self.led_on != led || self.last_tx != tx || self.last_rx != rx;
                if changed {
                    self.led_on = led;
                    self.last_tx = tx;
                    self.last_rx = rx;
                }
                changed
            }
            Msg::SetDisplayMode(mode) => {
                if self.display_mode != mode {
                    self.display_mode = mode;
                    true
                } else {
                    false
                }
            }
            Msg::ToggleHelp => {
                self.help_visible = !self.help_visible;
                true
            }
        }
