            s2_on: false,
            led_on: false,
            last_tx: None,
            last_rx: None,
            display_mode: DisplayMode::default(),
            help_visible: false,
            editor_visible: false,
            editor_text: String::new(),
            editor_dirty: false,
        }
    }

    fn update(&mut self, _ctx: &Context<Self>, msg: Self::Message) -> bool {
        match msg {
            Msg::Reset => {
                self.reset_seq = self.reset_seq.wrapping_add(1);
