.editor-textarea {
    flex: 1;
    resize: none;
    background: var(--base);
    color: var(--text);
    font-family: var(--mono);
    font-size: 15px;
    line-height: 1.5;
    padding: 12px 16px;
    border: none;
    outline: none;
    white-space: pre;
    overflow-y: auto;
    tab-size: 4;
    min-height: 120px;
}

.editor-textarea::placeholder {
    color: var(--overlay0);
}

.editor-preview {
    flex: 0 0 40%;
    overflow-y: auto;
    padding: 12px 16px;
    background: var(--crust);
    border-left: 1px solid var(--surface1);
    font-family: var(--mono);
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
}

.editor-preview-label {
    font-size: 11px;
    font-weight: 600;
    color: var(--overlay1);
    text-transform: uppercase;
    letter-spacing: 0.04em;
    margin-bottom: 8px;
}

.editor-preview-line {
    min-height: 1.5em;
}

/* Cursor blink animation */
@keyframes cursor-blink {
    0%, 49% { opacity: 1; }
    50%, 100% { opacity: 0; }
}

/* Responsive: narrow viewports */
@media (max-width: 600px) {
    .control-bar {
        flex-wrap: wrap;
        padding: 6px 10px;
        gap: 6px;
    }

    .hw-panel {
        position: static;
        margin: 0 10px 8px;
        border-radius: 4px;
    }

    .repl-output {
        padding: 8px 10px;
        font-size: 13px;
    }
}

@media (max-width: 400px) {
    .btn {
        font-size: 12px;
        padding: 3px 8px;
    }

    .demo-select {
        font-size: 11px;
        width: 100%;
    }
}

